template <stdx::ct_string name,
          std::uint32_t   baseaddress,
          std::uint32_t   offset>
using flash_flash_wrpsgn2r_cur_v1_tt =
  groov::reg<name,
             std::uint32_t,
             baseaddress + offset,
             common::access::rw,
               groov::field<"reserved0", std::uint32_t, 31, 8, common::access::ro>,
               groov::field<"wrpsg2", std::uint8_t, 7, 0, common::access::ro>>;

